// ===== Smart Normalization (optimized) =====

// Column name mapping rules
const columnMap = {
  "full name": "name",
  "email address": "email",
  "phone no": "phone",
  "amount ($)": "amount",
};

// Default schema template
const defaultSchema = {
  name: null,
  email: null,
  phone: null,
  amount: null,
  source_file: $json.filename || null,
  processed_at: new Date().toISOString(),
};

let normalized = {};

// Normalize each key/value
for (let [key, value] of Object.entries($json)) {

  // Key normalization: trim → lowercase → strip symbols → replace spaces with _
  let cleanKey = key.trim().toLowerCase()
    .replace(/[^a-z0-9 ]/g, "")
    .replace(/\s+/g, "_");

  // Apply mapping
  cleanKey = columnMap[cleanKey] || cleanKey;

  // Value normalization
  value = (value === "" || value === undefined || value === null)
    ? null
    : String(value).trim();

  normalized[cleanKey] = value;
}

// Merge with schema defaults
return { ...defaultSchema, ...normalized };

const items = $input.all();

for (const item of items) {
    let text = item.binary.data.toString('utf8');

    text = text.replace(/\r\n|\r/g, "\n");
    text = text.replace(/[ \t]+/g, " ");
    text = text.replace(/\n{3,}/g, "\n\n");
    text = text.replace(/[“”]/g, '"').replace(/[‘’]/g, "'");
    text = text.replace(/[^\x09\x0A\x0D\x20-\x7E]/g, "");
    text = text.split("\n").map(line => line.trim()).join("\n");

    item.json = { content: text };      // <-- FIXED field name
}

return items;

// Smart TXT Normalization for OCR Extracted Text (Personal AI Factory v1)

const raw = $json.text || "";

// Normalize, clean and format text
const normalized = raw
  .replace(/\r\n/g, "\n")        // Convert CRLF to LF
  .replace(/[ \t]+/g, " ")       // Normalize extra spaces
  .replace(/\n{3,}/g, "\n\n")    // Reduce >2 blank lines to max 1
  .replace(/[^\S\r\n]+/g, " ")   // Trim odd spacing without removing line breaks
  .replace(/\u00A0/g, " ")       // Replace non-breaking spaces
  .trim();

// Optional: remove repeating headers/footer patterns if needed
// Example cleanup for page artifacts:
const finalText = normalized
  .replace(/Page \d+ of \d+/gi, "")
  .replace(/Confidential/gi, "")
  .trim();

return [
  {
    json: {
      text: finalText
    }
  }
];

// YOUR_ID
// PERSONAL AI FACTORY v1 — KPI ENGINE
// Input: An array of JSON rows from CLEAN (CSV + JSON only)
// TXT files are ignored because they never reach this node
// YOUR_ID

const rows = items.map(i => i.json);

// If no rows (e.g., only TXT in CLEAN), produce empty KPIs
if (rows.length === 0) {
  const kpis = {
    win_rate: 0,
    avg_margin: 0,
    aging_days: 0,
    count_rows: 0
  };

  const csvRows = [
    { metric: 'win_rate', value: 0 },
    { metric: 'avg_margin', value: 0 },
    { metric: 'aging_days', value: 0 },
    { metric: 'count_rows', value: 0 }
  ];

  return [{ json: { kpis, csvRows, summary: "No structured rows available for KPI computation." }}];
}

// YOUR_ID
// Helpers
// YOUR_ID
const parseNumber = (value) => {
  if (value === undefined || value === null || value === "") return null;
  const cleaned = String(value).replace(/[,₹$]/g, '').trim();
  const num = Number(cleaned);
  return Number.isFinite(num) ? num : null;
};

const parseDate = (value) => {
  if (!value) return null;
  const d = new Date(value);
  return isNaN(d) ? null : d;
};

// Flexible mapping to handle different column names
const mapCol = (row, names) => {
  for (const n of names) {
    if (row[n] !== undefined && row[n] !== null && row[n] !== "") {
      return row[n];
    }
  }
  return null;
};

// YOUR_ID
// Normalize rows
// YOUR_ID
const normalized = rows.map(r => {
  return {
    status: (mapCol(r, ['status', 'state', 'result']) || "").toString().toLowerCase(),
    revenue: parseNumber(mapCol(r, ['revenue', 'amount', 'sale_value', 'price'])),
    cost: parseNumber(mapCol(r, ['cost', 'expense', 'cogs'])),
    created_at: parseDate(mapCol(r, ['created_at', 'created', 'date', 'timestamp']))
  };
});

// YOUR_ID
// Compute KPIs
// YOUR_ID

// Win Rate
const total = normalized.length;
const wins = normalized.filter(r =>
  r.status === 'won' ||
  r.status === 'closed-won' ||
  r.status === 'success'
).length;
const win_rate = total > 0 ? wins / total : 0;

// Average Margin
const margins = normalized
  .map(r => (r.revenue && r.cost !== null && r.revenue !== 0)
    ? (r.revenue - r.cost) / r.revenue
    : null)
  .filter(v => v !== null);

const avg_margin = margins.length > 0
  ? margins.reduce((a, b) => a + b, 0) / margins.length
  : 0;

// Aging Days
const now = new Date();
const daysBetween = (a, b) => Math.round((b - a) / (1000 * 60 * 60 * 24));

const ages = normalized
  .map(r => r.created_at ? daysBetween(r.created_at, now) : null)
  .filter(v => v !== null);

const aging_days = ages.length > 0
  ? Math.round(ages.reduce((a, b) => a + b, 0) / ages.length)
  : 0;

// YOUR_ID
// Output dataset for CSV
// YOUR_ID
const csvRows = [
  { metric: "win_rate", value: win_rate },
  { metric: "avg_margin", value: avg_margin },
  { metric: "aging_days", value: aging_days },
  { metric: "count_rows", value: total }
];

// YOUR_ID
// Final Output
// YOUR_ID
const summary = `Computed ${total} structured rows → win_rate=${(win_rate * 100).toFixed(1)}%, avg_margin=${(avg_margin * 100).toFixed(1)}%, aging_days=${aging_days}`;

return [{
  json: {
    kpis: {
      win_rate,
      avg_margin,
      aging_days,
      count_rows: total
    },
    csvRows,
    summary
  }
}];

// Get file meta from Download node
const fileMeta = $node["Google Drive — Download CLEAN file (for REPORT)"].json;

const rows = items.map(i => i.json);
const sampleRows = rows.slice(0, 5); // first 5 rows only

return [{
  json: {
    fileName: fileMeta.name,
    mimeType: fileMeta.mimeType,
    source: "csv",
    rowCount: rows.length,
    sampleRows,
  }
}];

const fileMeta = $node["Google Drive — Download CLEAN file (for REPORT)"].json;

const rows = items.map(i => i.json);
const sampleRows = rows.slice(0, 5);

return [{
  json: {
    fileName: fileMeta.name,
    mimeType: fileMeta.mimeType,
    source: "json",
    rowCount: rows.length,
    sampleRows,
  }
}];

const fileMeta = $node["Google Drive — Download CLEAN file (for REPORT)"].json;

// Depending on Extract node, the text might be in json, json.data, or similar
const raw = items[0].json.data ?? items[0].json ?? "";

let text;
if (typeof raw === 'string') {
  text = raw;
} else {
  // If it's an object/array, stringify it so GPT still sees the content
  text = JSON.stringify(raw, null, 2);
}

return [{
  json: {
    fileName: fileMeta.name,
    mimeType: fileMeta.mimeType,
    source: "txt",
    textPreview: text.slice(0, 2000)  // cap length
  }
}];

// We expect a single item from "Extract from CSV File from GOLD (for REPORT)"
const item = (items[0] && items[0].json) || {};

// 1) Rebuild the KPIs object from fields like "kpis.win_rate", "kpis.avg_margin", ...
const kpis = {};

// Case A: if extractor already gives a nested "kpis" object
if (item.kpis && typeof item.kpis === 'object') {
  for (const [metric, raw] of Object.entries(item.kpis)) {
    let value = raw;
    if (typeof value === 'string') {
      const n = Number(value);
      value = isNaN(n) ? value : n;
    }
    kpis[metric] = value;
  }
} else {
  // Case B: flattened keys like "kpis.win_rate"
  for (const key of Object.keys(item)) {
    if (!key.startsWith('kpis.')) continue;

    const metric = key.slice('kpis.'.length); // e.g. "win_rate"
    let value = item[key];

    if (typeof value === 'string') {
      const n = Number(value);
      value = isNaN(n) ? value : n;
    }

    kpis[metric] = value;
  }
}

// Optional extras: summary text from the KPI CSV (if present)
const summary = item.summary || null;

// Metadata about the KPI file from the Download node
const fileMeta = $node["Google Drive — Download Gold file (for REPORT)"].json;

return [{
  json: {
    kpis,
    kpiSource: {
      fileName: fileMeta.name,
      fileId: fileMeta.id,
    },
    summary,   // optional, can be used in the REPORT prompt
  }
}];

// Gather ALL processed samples coming from Split In Batches (Done Output)
const samples = $input.all().map(i => i.json);

return [{
  json: {
    cleanSummary: {
      fileCount: samples.length,
      files: samples,
    }
  }
}];

