// Extract the text returned by Gemini
const geminiOutput = $json.text || "";

// Build YYYY-MM-DD manually to avoid timezone issues
const d = new Date();
const year = d.getFullYear();
const month = String(d.getMonth() + 1).padStart(2, "0");
const day = String(d.getDate()).padStart(2, "0");
const today = `${year}-${month}-${day}`;

// Filename format: YYYY-MM-DD_REPORT.txt (e.g., 2025-12-07_REPORT.txt)
const reportFileName = `${today}_REPORT.txt`;

// Output structured data for next node
return [
  {
    json: {
      reportText: geminiOutput,
      reportFileName,
    }
  }
];

/**
 * Unified Build Response for INGEST agent
 * Personal AI Factory v1 — Recommended Production Version
 */

// Normalizes a drive link or returns null
const normalizeLink = (v) =>
  (typeof v === 'string' && v.trim().startsWith('http')) ? v.trim() : null;

// Extract all rows safely
const rows = (items || [])
  .map(i => i?.json || {})
  .filter(r => Object.keys(r).length > 0);

// Count success/failure
const successes = rows.filter(r => String(r.status).toLowerCase() === 'success');
const failures  = rows.filter(r => String(r.status).toLowerCase() !== 'success');

// Extract valid drive links (for returning to GPT + pipeline)
const links = successes
  .map(r => normalizeLink(r.output))
  .filter(Boolean);

// ----- Build Summary Message -----
let summary;
if (rows.length === 0) {
  summary = `INGEST agent ran, but no attachments were found to ingest.`;
} else if (failures.length === 0) {
  summary = `INGEST agent successfully saved ${successes.length} attachment(s) to RAW.`;
} else if (successes.length === 0) {
  summary = `INGEST agent attempted ingestion but all attachments failed.`;
} else {
  summary = `INGEST agent saved ${successes.length} attachment(s) to RAW, `
          + `but ${failures.length} attachment(s) failed.`;
}

// ----- Determine OK State -----
const ok = failures.length === 0;

// ----- Useful meta info for advanced reporting (future proof) -----
const meta = {
  totalProcessed: rows.length,
  successes: successes.length,
  failures: failures.length,
  agent: "ingest",
};

// ----- Return Standardized v1 Contract -----
return [{
  json: {
    ok,
    summary,
    kpis: {},        // INGEST never produces KPIs
    links,           // list of RAW file links
    meta,            // extra info (OPTIONAL but safe + useful)
  },
}];

/**
 * Function – Build Response (CLEAN agent) v1.1 [FIXED STATUS LOGIC]
 * Mode: Run Once for All Items
 * Input: items[] from "Split In Batches — FOR EACH RAW FILE" DONE branch
 * Each item.json ≈ { agent, ts, action, status, notes, output, input }
 */

// YOUR_ID
// UTILITY HELPERS
// YOUR_ID

// Normalize a link or drop it
const normalizeLink = (v) =>
  (typeof v === 'string' && v.trim().startsWith('http')) ? v.trim() : null;

// Infer extension from input filename
const getExt = (name) => {
  if (typeof name !== 'string') return null;
  const m = name.toLowerCase().match(/\.([0-9a-z]+)(?:\?|$)/);
  return m ? m[1] : null;
};

// CLEAN agent success logic (IMPORTANT FIX)
// Accepts "success" or "clean_success"
const isSuccessStatus = (s) => {
  const v = String(s || '').toLowerCase();
  return v === 'success' || v === 'clean_success';
};

// YOUR_ID
// COLLECT RECORDS
// YOUR_ID

const rows = (items || [])
  .map(i => i?.json || {})
  .filter(r => Object.keys(r).length > 0);

// Split into success / failure using FIXED logic
const successes = rows.filter(r => isSuccessStatus(r.status));
const failures  = rows.filter(r => !isSuccessStatus(r.status));

// Collect CLEAN links
const links = successes
  .map(r => normalizeLink(r.output))
  .filter(Boolean);

// Optional type statistics
const typeCounts = {};
for (const r of rows) {
  const ext = getExt(r.input) || 'unknown';
  typeCounts[ext] = (typeCounts[ext] || 0) + 1;
}

// YOUR_ID
// HUMAN SUMMARY MESSAGE
// YOUR_ID

let summary;
if (rows.length === 0) {
  summary = 'CLEAN agent ran, but no RAW files were found to normalize.';
} else if (failures.length === 0) {
  summary = `CLEAN agent successfully normalized ${successes.length} file(s) from RAW to CLEAN.`;
} else if (successes.length === 0) {
  summary = `CLEAN agent attempted normalization but all ${failures.length} file(s) failed.`;
} else {
  summary = `CLEAN agent normalized ${successes.length} file(s) to CLEAN, `
          + `but ${failures.length} file(s) failed.`;
}

// YOUR_ID
// OUTPUT (Standard v1 Contract)
// YOUR_ID

const ok = failures.length === 0;

const meta = {
  agent: 'clean',
  totalProcessed: rows.length,
  successes: successes.length,
  failures: failures.length,
  typeCounts,                  // e.g. { csv: 2, txt: 2, json: 1 }
  inputs: rows.map(r => r.input),  // original filenames
};

return [{
  json: {
    ok,
    summary,
    kpis: {},      // CLEAN agent does not compute KPIs
    links,         // links to CLEAN files (CSV/TXT/JSON etc.)
    meta,          // useful diagnostics + dashboards
  },
}];

/**
 * Function – Build Response (ANALYZE agent) v1.1 [FIXED STATUS LOGIC]
 * Mode: Run Once for All Items
 *
 * Input (items[]): from EVENT_LOG append (analyze_success)
 * Each item.json ≈ { ts, agent, input, output, status, action, notes }
 *
 * Also reads KPIs from the KPI Code node.
 */

// ---------- helpers ----------
const normalizeLink = (v) =>
  (typeof v === 'string' && v.trim().startsWith('http')) ? v.trim() : null;

// Treat both "success" and "analyze_success" as success
const isSuccessStatus = (s) => {
  const v = String(s || '').toLowerCase();
  return v === 'success' || v === 'analyze_success';
};

// ---------- collect EVENT_LOG rows ----------
const rows = (items || [])
  .map(i => i?.json || {})
  .filter(r => Object.keys(r).length > 0);

const successes = rows.filter(r => isSuccessStatus(r.status));
const failures  = rows.filter(r => !isSuccessStatus(r.status));

// GOLD file links (kpi.csv)
const links = successes
  .map(r => normalizeLink(r.output))
  .filter(Boolean);

// ---------- get KPIs from KPI node ----------
let kpis = {};
try {
  // Change this name to the EXACT name of your KPI code node
  const kpiNode = $node["Function Node — Compute KPIs"].json;

  if (kpiNode && typeof kpiNode === 'object') {
    if (kpiNode.kpis && typeof kpiNode.kpis === 'object') {
      kpis = kpiNode.kpis;
    } else {
      // fallback: treat full node json as KPI object
      kpis = kpiNode;
    }
  }
} catch (e) {
  kpis = {};
}

// Optional: build small human-readable KPI snippet
const parts = [];
if (typeof kpis.win_rate === 'number') {
  parts.push(`win rate: ${(kpis.win_rate * 100).toFixed(1)}%`);
}
if (typeof kpis.avg_margin === 'number') {
  parts.push(`avg margin: ${(kpis.avg_margin * 100).toFixed(1)}%`);
}
if (typeof kpis.aging_days === 'number') {
  parts.push(`aging: ${Math.round(kpis.aging_days)} days`);
}
if (typeof kpis.count_rows === 'number') {
  parts.push(`rows: ${kpis.count_rows}`);
}
const kpiSummary = parts.length ? ` (${parts.join(", ")})` : "";

// ---------- summary ----------
let summary;
if (rows.length === 0) {
  summary = "ANALYZE agent ran, but no CLEAN data was found to compute KPIs.";
} else if (failures.length === 0) {
  summary = `ANALYZE agent successfully computed KPIs and wrote kpi.csv to GOLD${kpiSummary}.`;
} else if (successes.length === 0) {
  summary = "ANALYZE agent attempted KPI computation, but it failed.";
} else {
  summary = "ANALYZE agent computed KPIs with partial success; check EVENT_LOG for details.";
}

// ---------- ok + meta ----------
const ok = failures.length === 0;

const meta = {
  agent: "analyze",
  totalEvents: rows.length,
  successes: successes.length,
  failures: failures.length,
  kpiFile: (successes[0]?.input) || (rows[0]?.input) || "kpi.csv",
};

// ---------- standard v1 response ----------
return [{
  json: {
    ok,
    summary,
    kpis,    // KPI object for Reporter and GPT
    links,   // link(s) to kpi.csv in GOLD
    meta,    // extra diagnostics (optional)
  },
}];

/**
 * Function – Build Response (REPORT agent) v1.1 [FIXED STATUS LOGIC]
 * Mode: Run Once for All Items
 *
 * Input: items[] from "Google Sheets — Append EVENT_LOG (report_success)"
 * Each item.json ≈ {
 *   ts, agent, input, output, status, action, notes
 * }
 *
 * Also reads:
 *   - LLM summary from node "Basic LLM Chain"
 *   - KPIs from node "Function Node — Build Values from GOLD KPIs"
 */

// ---------- helpers ----------
const normalizeLink = (v) =>
  (typeof v === 'string' && v.trim().startsWith('http')) ? v.trim() : null;

// robust success check
const isSuccessStatus = (s) => {
  const v = String(s || '').toLowerCase();
  return v.includes('success');            // <-- accepts report_success / generate_report_success
};

// ---------- collect EVENT_LOG rows ----------
const rows = (items || [])
  .map(i => i?.json || {})
  .filter(r => Object.keys(r).length > 0);

const successes = rows.filter(r => isSuccessStatus(r.status));
const failures  = rows.filter(r => !isSuccessStatus(r.status));

// ---------- extract report file link(s) ----------
const reportLinks = [];

for (const r of rows) {
  const out = r.output;

  if (!out) continue;

  // Case 1: output is a string URL
  if (typeof out === 'string') {
    const link = normalizeLink(out);
    if (link) reportLinks.push(link);
    continue;
  }

  // Case 2: Drive metadata under output.json
  if (out.json && out.json.webViewLink) {
    const link = normalizeLink(out.json.webViewLink);
    if (link) reportLinks.push(link);
  }

  // Case 3: Drive metadata under output.data
  if (out.data && out.data.webViewLink) {
    const link = normalizeLink(out.data.webViewLink);
    if (link) reportLinks.push(link);
  }
}

// Remove duplicates
const links = Array.from(new Set(reportLinks));

// ---------- get LLM summary (Gemini) ----------
let summaryText = '';

try {
  // Change this name EXACTLY to your LLM node name
  const llmNode = $node["Basic LLM Chain"].json;

  if (llmNode && typeof llmNode === 'object') {
    summaryText = llmNode.text || llmNode.summary || '';
  }
} catch (e) {
  summaryText = '';
}

// ---------- get structured KPIs ----------
let kpis = {};
try {
  const kNode = $node["Function Node — Build Values from GOLD KPIs"].json;

  if (kNode && typeof kNode === 'object') {
    if (kNode.kpis && typeof kNode.kpis === 'object') {
      kpis = kNode.kpis;
    } else {
      kpis = kNode;
    }
  }
} catch (e) {
  kpis = {};
}

// ---------- build final summary ----------
let summary;
if (!summaryText) {
  if (rows.length === 0) {
    summary = 'REPORT agent ran but no summary text was generated.';
  } else {
    summary = 'REPORT agent generated a file, but summary text could not be retrieved.';
  }
} else {
  summary = summaryText;
}

// ok = MUST have success AND MUST have summary
const ok = successes.length > 0 && !!summaryText;

// ---------- meta diagnostics ----------
const meta = {
  agent: 'report',
  totalEvents: rows.length,
  successes: successes.length,
  failures: failures.length,
  reportFileName: successes[0]?.input || null,
};

// ---------- standard v1 response ----------
return [{
  json: {
    ok,
    summary,
    kpis,
    links,
    meta,
  },
}];
